import pytest
from hypothesis import given, strategies as st
from sympy.series.sequences import SeqBase

# Create a minimal SeqBase instance for testing
class DummySeq(SeqBase):
    def __init__(self, start=-10, stop=10):
        self._start = start
        self._stop = stop
        super().__init__()

    @property
    def start(self):
        return self._start

    @property
    def stop(self):
        return self._stop

    def _eval_coeff(self, pt):
        # Simple deterministic implementation for testing
        return pt * 2

@given(pt=st.integers(min_value=-10, max_value=10))
def test_coeff_returns_coefficient(pt):
    """Test that coeff returns the coefficient at point pt."""
    seq = DummySeq(start=-10, stop=10)
    result = seq.coeff(pt)
    # Based on the docstring, coeff should return a coefficient
    # Using the dummy implementation, verify it returns pt * 2
    assert result == pt * 2

if __name__ == "__main__":
    pytest.main([__file__, "-v"])

import pytest
from hypothesis import given, strategies as st
from sympy.series.sequences import sequence
from sympy import SeqPer, SeqFormula, symbols

@given(
    seq=st.one_of(
        st.tuples(st.integers(min_value=-10, max_value=10), st.integers(min_value=-10, max_value=10), st.integers(min_value=-10, max_value=10)),
        st.builds(lambda: symbols('n')**2)
    ),
    limits=st.tuples(st.just(symbols('n')), st.integers(min_value=0, max_value=5), st.integers(min_value=0, max_value=5))
)
def test_sequence_returns_correct_type(seq, limits):
    """Property: sequence returns SeqPer for tuple seq, SeqFormula for expression seq."""
    result = sequence(seq, limits)
    if isinstance(seq, tuple):
        assert isinstance(result, SeqPer), f"Expected SeqPer for tuple seq {seq}, got {type(result)}"
    else:
        assert isinstance(result, SeqFormula), f"Expected SeqFormula for expression seq {seq}, got {type(result)}"

if __name__ == "__main__":
    pytest.main([__file__, "-v"])

import pytest
from hypothesis import given, strategies as st
from sympy.crypto.crypto import check_and_join

@given(
    phrase=st.text(min_size=0, max_size=10),
