)
def test_check_and_join_no_symbols_no_error(phrase, symbols):
    """When symbols is None, function should return joined string without raising errors."""
    result = check_and_join(phrase, symbols)
    assert result == phrase

@given(
    phrase=st.text(min_size=1, max_size=10),
    symbols=st.text(min_size=1, max_size=10)
)
def test_check_and_join_with_symbols_valid(phrase, symbols):
    """When all characters in phrase are in symbols, function should return joined string."""
    # Filter phrase to only contain characters from symbols
    filtered_phrase = ''.join([c for c in phrase if c in symbols])
    if filtered_phrase:
        result = check_and_join(filtered_phrase, symbols)
        assert result == filtered_phrase

@given(
    phrase=st.text(min_size=1, max_size=10),
    symbols=st.text(min_size=1, max_size=10)
)
def test_check_and_join_with_symbols_invalid(phrase, symbols):
    """When phrase contains characters not in symbols, function should raise ValueError."""
    # Ensure phrase has at least one character not in symbols
    if any(c not in symbols for c in phrase):
        with pytest.raises(ValueError, match="characters in phrase but not symbols"):
            check_and_join(phrase, symbols)

