@given(
    a=st.one_of(
        st.integers(),
        st.floats(allow_nan=False, allow_infinity=False),
        st.text(min_size=1, alphabet=st.characters(whitelist_categories=('L', 'N', 'P', 'S', 'Z')))
    ),
