)
def test_sympify_strict_string_behavior(a, strict):
    """Property: When strict=True and a is a string, sympify raises SympifyError."""
    if strict and isinstance(a, str):
        with pytest.raises(SympifyError):
            sympify(a, strict=strict)
    else:
        try:
            result = sympify(a, strict=strict)
            assert result is not None
        except SympifyError:
            pytest.fail(f"Unexpected SympifyError for a={repr(a)}, strict={strict}")

import pytest
from hypothesis import given, strategies as st
from sympy.core.containers import Tuple

@given(
    elements=st.lists(st.integers(), min_size=1, max_size=10),
    value=st.integers(),
    start=st.one_of(st.none(), st.integers(min_value=-10, max_value=20)),
    stop=st.one_of(st.none(), st.integers(min_value=-10, max_value=20))
)
def test_Tuple_index_returns_first_occurrence(elements, value, start, stop):
    """Property: Tuple.index(value, start, stop) returns the first index of value within the specified slice."""
    t = Tuple(*elements)
    try:
        result = t.index(value, start, stop)
        # Verify result is within bounds
        assert isinstance(result, int)
        assert result >= 0
        # Check that value at result matches
        assert t[result] == value
        # Verify it's the first occurrence in the slice
        if start is None:
            start_idx = 0
        else:
            start_idx = start if start >= 0 else max(0, len(t) + start)
        if stop is None:
            stop_idx = len(t)
        else:
            stop_idx = stop if stop >= 0 else max(0, len(t) + stop)
        start_idx = max(0, min(start_idx, len(t)))
        stop_idx = max(start_idx, min(stop_idx, len(t)))
        for i in range(start_idx, stop_idx):
            if t[i] == value:
                assert i == result
                break
    except ValueError:
        # If ValueError is raised, value must not be in the slice
        if start is None:
            start_idx = 0
        else:
            start_idx = start if start >= 0 else max(0, len(t) + start)
        if stop is None:
            stop_idx = len(t)
        else:
            stop_idx = stop if stop >= 0 else max(0, len(t) + stop)
        start_idx = max(0, min(start_idx, len(t)))
        stop_idx = max(start_idx, min(stop_idx, len(t)))
        for i in range(start_idx, stop_idx):
            assert t[i] != value

if __name__ == "__main__":
    pytest.main([__file__, "-v"])

import pytest
from hypothesis import given, strategies as st
from more_itertools.more import peekable

@given(iterable=st.lists(st.integers(), max_size=5))
def test_peek_returns_next_item(iterable):
    """peek() should return the item that will be next returned from next()."""
    p = peekable(iterable)
    if iterable:
        assert p.peek() == iterable[0]
        assert p.peek() == iterable[0]  # Should be idempotent
        assert next(p) == iterable[0]
    else:
        with pytest.raises(StopIteration):
            p.peek()

@given(iterable=st.lists(st.integers(), max_size=5), default=st.integers())
def test_peek_with_default(iterable, default):
    """peek(default) should return default if there are no items left."""
    p = peekable(iterable)
    for _ in range(len(iterable)):
        next(p)
    assert p.peek(default) == default

@given(iterable=st.lists(st.integers(), max_size=5))
def test_peek_does_not_consume(iterable):
    """peek() should not advance the iterator."""
    p = peekable(iterable)
    if iterable:
        peeked = p.peek()
        assert next(p) == peeked
        if len(iterable) > 1:
            assert next(p) == iterable[1]
    else:
        with pytest.raises(StopIteration):
            p.peek()

