    if len(items) > n:
        with pytest.raises(ValueError) as exc_info:
            list(strictly_n(items, n))
        assert "too many" in str(exc_info.value).lower() or "Too many" in str(exc_info.value)

@given(
    items=st.lists(st.integers(), min_size=0, max_size=5),
    n=st.integers(min_value=6, max_value=10)
)
def test_strictly_n_too_short_custom_called(items, n):
    """Property: When iterable length < n, custom too_short is called with item count."""
    if len(items) < n:
        call_count = [0]
        call_arg = [None]
        def custom_too_short(item_count):
            call_count[0] += 1
            call_arg[0] = item_count
            raise RuntimeError
        with pytest.raises(RuntimeError):
