import pytest
from hypothesis import given, strategies as st
from more_itertools.more import sliced

@given(
    seq=st.lists(st.integers(), min_size=0, max_size=20),
    n=st.integers(min_value=1, max_value=10),
    strict=st.booleans()
)
def test_sliced_yields_correct_number_of_slices(seq, n, strict):
    """Property: The number of slices yielded equals ceil(len(seq)/n) when not strict, or raises ValueError if strict and len(seq) % n != 0."""
    import math

    if strict and len(seq) % n != 0:
        with pytest.raises(ValueError):
            list(sliced(seq, n, strict=strict))
    else:
        result = list(sliced(seq, n, strict=strict))
        expected_slices = math.ceil(len(seq) / n) if n > 0 else 0
        assert len(result) == expected_slices

@given(
    seq=st.lists(st.integers(), min_size=0, max_size=20),
    n=st.integers(min_value=1, max_value=10)
)
def test_sliced_slice_lengths(seq, n):
    """Property: All slices except possibly the last have length n, and the last slice has length len(seq) % n (or n if divisible)."""
    result = list(sliced(seq, n, strict=False))
    if not result:
        return

    for i, slice_ in enumerate(result[:-1]):
        assert len(slice_) == n

    last_slice = result[-1]
    remainder = len(seq) % n
    expected_last_length = remainder if remainder != 0 else n
    assert len(last_slice) == expected_last_length

@given(
    seq=st.lists(st.integers(), min_size=0, max_size=20),
    n=st.integers(min_value=1, max_value=10)
)
def test_sliced_preserves_sequence_order(seq, n):
    """Property: Concatenating all yielded slices reconstructs the original sequence."""
    result = list(sliced(seq, n, strict=False))
    reconstructed = []
    for slice_ in result:
        reconstructed.extend(slice_)
    assert reconstructed == seq

import pytest
from hypothesis import given, strategies as st
from more_itertools.more import split_when

@given(
    iterable=st.lists(st.integers(), min_size=0, max_size=10),
    maxsplit=st.integers(min_value=-1, max_value=5)
)
def test_split_when_maxsplit_limit(iterable, maxsplit):
    """The number of resulting pieces should be at most maxsplit+1 when maxsplit >= 0."""
    # Use a predicate that never splits to isolate maxsplit behavior
    def false_pred(x, y):
        return False

    result = list(split_when(iterable, false_pred, maxsplit=maxsplit))

    if maxsplit >= 0:
        # With a never-splitting predicate, maxsplit limits splits to at most maxsplit
        # So pieces <= maxsplit + 1
        assert len(result) <= maxsplit + 1
    else:
        # maxsplit=-1 means no limit, but with never-splitting predicate,
        # result should be exactly one piece unless iterable is empty
        if iterable:
            assert len(result) == 1
        else:
            # Empty iterable yields empty list
            assert result == []

@given(
    iterable=st.lists(st.integers(), min_size=2, max_size=10),
    pred=st.functions(like=lambda x, y: False, returns=st.booleans(), pure=True)
)
def test_split_when_predicate_consistency(iterable, pred):
    """Splits should occur exactly where pred returns True for consecutive pairs."""
    result = list(split_when(iterable, pred, maxsplit=-1))

    # Flatten result to reconstruct original iterable
    reconstructed = []
    for piece in result:
        reconstructed.extend(piece)
    assert reconstructed == iterable

    # Check splits align with predicate
    # For each piece, check internal consecutive pairs
    for piece in result:
        for i in range(len(piece) - 1):
            # pred should be False within a piece
            # Use the actual predicate with the pair
            x, y = piece[i], piece[i+1]
            # The predicate must be deterministic; we assume pure=True ensures this
            assert not pred(x, y), f"Predicate returned True within piece at ({x}, {y})"

    # Check between pieces (if multiple pieces)
    if len(result) > 1:
        for i in range(len(result) - 1):
            last_of_piece = result[i][-1]
            first_of_next = result[i+1][0]
            # pred should be True at split points
            assert pred(last_of_piece, first_of_next), f"Predicate returned False at split between ({last_of_piece}, {first_of_next})"

