from hypothesis import given, strategies as st
from more_itertools.more import unzip

@given(st.lists(st.tuples(st.integers(), st.text()), min_size=1))
def test_unzip_inverse_of_zip(iterable):
    """Test that unzip is the inverse of zip for the first element's length."""
    # Unzip the iterable
    unzipped = unzip(iterable)
    unzipped_lists = [list(u) for u in unzipped]

    # Re-zip the unzipped results
    rezipped = list(zip(*unzipped_lists))

    # The rezipped result should equal the original iterable
    assert rezipped == iterable

@given(st.lists(st.tuples(st.integers(), st.text()), min_size=1))
def test_unzip_lengths_match(iterable):
    """Test that all unzipped iterables have the same length as the input."""
    unzipped = unzip(iterable)
    unzipped_lists = [list(u) for u in unzipped]

    # All unzipped lists should have the same length as the input iterable
    for lst in unzipped_lists:
        assert len(lst) == len(iterable)

@given(st.lists(st.tuples(st.integers(), st.text()), min_size=1))
def test_unzip_preserves_order(iterable):
    """Test that unzip preserves the order of elements from the input."""
    unzipped = unzip(iterable)
    unzipped_lists = [list(u) for u in unzipped]

    # Check that the i-th element of each unzipped list matches the i-th tuple
    for i, tup in enumerate(iterable):
        for j, lst in enumerate(unzipped_lists):
            assert lst[i] == tup[j]

import pytest
from hypothesis import given, strategies as st
from more_itertools.more import rstrip

@given(
    iterable=st.lists(st.integers(), max_size=10),
    pred=st.functions(like=lambda x: x % 2 == 0, returns=st.booleans(), pure=True)
)
def test_rstrip_removes_trailing_matching_items(iterable, pred):
    """Property: rstrip removes all trailing items where pred returns True, and keeps all others."""
    result = list(rstrip(iterable, pred))

    # Check that no trailing items in result satisfy pred
    if result:
        # Find the last index from the end where pred is False
        last_non_matching_index = None
        for i in range(len(result) - 1, -1, -1):
            if not pred(result[i]):
                last_non_matching_index = i
                break

        # If all items match pred, result should be empty
        if last_non_matching_index is None:
            assert len(result) == 0, f"All items match pred but result is non-empty: {result}"
        else:
            # Verify no items after last_non_matching_index match pred
            for i in range(last_non_matching_index + 1, len(result)):
                assert not pred(result[i]), f"Trailing item {result[i]} at index {i} matches pred in result"

    # Check that result is a prefix of the original iterable
    # (i.e., items are removed only from the end)
    for i, (orig, res) in enumerate(zip(iterable, result)):
        assert orig == res, f"Mismatch at position {i}: original {orig} != result {res}"

    # Ensure result length <= original length
    assert len(result) <= len(iterable), f"Result longer than original: {len(result)} > {len(iterable)}"

if __name__ == "__main__":
    pytest.main([__file__, "-v"])

