from hypothesis import given, strategies as st
from more_itertools.more import partitions

@given(st.lists(st.integers(), min_size=1, max_size=5))
def test_partitions_preserves_order(iterable):
    """Test that each partition preserves the original order of elements."""
    for partition in partitions(iterable):
        flattened = [item for part in partition for item in part]
        assert flattened == list(iterable)

@given(st.lists(st.integers(), min_size=1, max_size=5))
def test_partitions_covers_all_elements(iterable):
    """Test that all elements appear exactly once across each partition."""
    for partition in partitions(iterable):
        total_elements = sum(len(part) for part in partition)
        assert total_elements == len(iterable)
        all_elements = [item for part in partition for item in part]
        assert all_elements == list(iterable)

@given(st.lists(st.integers(), min_size=1, max_size=5))
def test_partitions_non_empty_parts(iterable):
    """Test that each part in a partition is non-empty."""
    for partition in partitions(iterable):
        for part in partition:
            assert len(part) > 0

@given(st.lists(st.integers(), max_size=5))
def test_partitions_empty_iterable(iterable):
    """Test that partitions of an empty iterable yields a single empty partition."""
    if not iterable:
        result = list(partitions(iterable))
        assert len(result) == 1
        assert result[0] == ()
        for partition in partitions(iterable):
            assert partition == ()
            for part in partition:
                assert len(part) == 0

import pytest
from hypothesis import given, strategies as st
from more_itertools.more import filter_except

@given(
    items=st.lists(st.integers(min_value=-5, max_value=15), min_size=0, max_size=5),
    exceptions=st.lists(st.sampled_from([ValueError, TypeError, ZeroDivisionError]), min_size=0, max_size=3, unique=True)
)
def test_filter_except_yields_items_where_validator_does_not_raise_specified_exceptions(items, exceptions):
    """Property: filter_except yields items from iterable where validator does not raise specified exceptions."""
    def validator(x):
        if x == 0:
            raise ZeroDivisionError
        if x < 0:
            raise ValueError
        if x > 10:
            raise TypeError
        return True

    result = list(filter_except(validator, items, *exceptions))

    for item in items:
        try:
            validator(item)
            # If validator does not raise, item should be in result
            assert item in result
        except Exception as e:
            # If validator raises an exception, check if it's in exceptions
            if type(e) in exceptions:
                # If exception is specified, item should not be in result
                assert item not in result
            else:
                # If exception is not specified, it should have been raised and not caught
                # This means the function should propagate the exception, but in list() it would stop iteration
                # For property test, we ensure such items are not in result
                assert item not in result

    # Additional check: all items in result should have passed validator without raising specified exceptions
    for item in result:
        try:
            validator(item)
        except Exception as e:
            assert type(e) not in exceptions  # Should not raise a specified exception

if __name__ == "__main__":
    pytest.main([__file__, "-v"])

import pytest
from hypothesis import given, strategies as st
