    """Property: Raises IndexError if index is out of bounds for permutations."""
    if 0 <= r <= len(iterable):
        max_index = 1
        for i in range(r):
            max_index *= (len(iterable) - i)
        if index >= max_index:
            with pytest.raises(IndexError):
                nth_permutation(iterable, r, index)
        else:
            try:
                nth_permutation(iterable, r, index)
            except (ValueError, IndexError):
                pass

