import pytest
from hypothesis import given, strategies as st
from more_itertools.more import unique_in_window

@given(
    iterable=st.lists(st.integers(min_value=0, max_value=10), min_size=0, max_size=20),
    n=st.integers(min_value=1, max_value=10)
)
def test_unique_in_window_yields_items_not_in_recent_input_window(iterable, n):
    """Property: Each yielded item should not appear in the previous n items of the input."""
    result = list(unique_in_window(iterable, n))

    # Track input positions for yielded items
    input_index = 0
    last_n_inputs = []  # Maintain last n inputs seen
    for item in result:
        # Find the next occurrence of item in iterable starting from input_index
        while input_index < len(iterable) and iterable[input_index] != item:
            last_n_inputs.append(iterable[input_index])
            if len(last_n_inputs) > n:
                last_n_inputs.pop(0)
            input_index += 1
        if input_index >= len(iterable):
            break  # Should not happen if result is correct
        # Check that item is not in last_n_inputs
        assert item not in last_n_inputs, f"Item {item} at input index {input_index} appears in recent input window {last_n_inputs}"
        # Update last_n_inputs with current item
        last_n_inputs.append(item)
        if len(last_n_inputs) > n:
            last_n_inputs.pop(0)
        input_index += 1

@given(
    iterable=st.lists(st.text(min_size=1, max_size=1, alphabet='abc'), min_size=0, max_size=20),
    n=st.integers(min_value=1, max_value=10),
    key=st.just(lambda x: x.lower())
)
def test_unique_in_window_with_key_function_input_window(iterable, n, key):
    """Property: With key function, uniqueness is determined by key(item) in the input window."""
    result = list(unique_in_window(iterable, n, key))

    input_index = 0
    last_n_keys = []
    for item in result:
        while input_index < len(iterable) and key(iterable[input_index]) != key(item):
            last_n_keys.append(key(iterable[input_index]))
            if len(last_n_keys) > n:
                last_n_keys.pop(0)
            input_index += 1
        if input_index >= len(iterable):
            break
        key_item = key(item)
        assert key_item not in last_n_keys, f"Key {key_item} of item {item} at input index {input_index} appears in recent input window {last_n_keys}"
        last_n_keys.append(key_item)
        if len(last_n_keys) > n:
            last_n_keys.pop(0)
        input_index += 1

import pytest
from hypothesis import given, strategies as st
from more_itertools.more import iter_suppress

@given(
    items=st.lists(st.integers(min_value=0, max_value=10), min_size=0, max_size=5),
    exception_type=st.sampled_from([ValueError, TypeError, RuntimeError])
)
def test_iter_suppress_yields_items_until_exception(items, exception_type):
    """Test that iter_suppress yields items from iterable until specified exception is raised."""
    class RaisingIterator:
        def __init__(self, items, exc_type):
            self.items = items
            self.exc_type = exc_type
            self.index = 0

        def __iter__(self):
            return self

        def __next__(self):
            if self.index < len(self.items):
                value = self.items[self.index]
                self.index += 1
                return value
            else:
                raise self.exc_type("Test exception")

    iterator = RaisingIterator(items, exception_type)
    result = list(iter_suppress(iterator, exception_type))

    assert result == items

@given(
    items=st.lists(st.integers(min_value=0, max_value=10), min_size=0, max_size=5),
    exception_type=st.sampled_from([ValueError, TypeError, RuntimeError])
)
def test_iter_suppress_suppresses_specified_exception(items, exception_type):
    """Test that iter_suppress suppresses only the specified exception(s)."""
    class RaisingIterator:
        def __init__(self, items, exc_type):
            self.items = items
            self.exc_type = exc_type
            self.index = 0

        def __iter__(self):
            return self

        def __next__(self):
            if self.index < len(self.items):
                value = self.items[self.index]
                self.index += 1
                return value
            else:
                raise self.exc_type("Test exception")

    iterator = RaisingIterator(items, exception_type)

    # Should not raise the specified exception
    result = list(iter_suppress(iterator, exception_type))
    assert result == items

    # Different exception should propagate
    different_exception = RuntimeError if exception_type != RuntimeError else ValueError
    iterator2 = RaisingIterator(items, different_exception)
    with pytest.raises(different_exception):
        list(iter_suppress(iterator2, exception_type))

@given(
    items=st.lists(st.integers(min_value=0, max_value=10), min_size=0, max_size=5)
)
def test_iter_suppress_without_exception(items):
    """Test that iter_suppress behaves like normal iteration when no exception is raised."""
    result = list(iter_suppress(iter(items)))
    assert result == items

@given(
    items=st.lists(st.integers(min_value=0, max_value=10), min_size=0, max_size=5),
    exception_types=st.lists(st.sampled_from([ValueError, TypeError, RuntimeError]), min_size=1, max_size=3, unique=True)
)
def test_iter_suppress_multiple_exceptions(items, exception_types):
    """Test that iter_suppress can suppress multiple exception types."""
    class RaisingIterator:
        def __init__(self, items, exc_type):
            self.items = items
            self.exc_type = exc_type
            self.index = 0

        def __iter__(self):
            return self

        def __next__(self):
            if self.index < len(self.items):
                value = self.items[self.index]
                self.index += 1
                return value
            else:
                raise self.exc_type("Test exception")

    # Test with each exception type in the list
    for exc_type in exception_types:
        iterator = RaisingIterator(items, exc_type)
        result = list(iter_suppress(iterator, *exception_types))
        assert result == items

