import pytest
from hypothesis import given, strategies as st
from more_itertools.recipes import roundrobin

@given(st.lists(st.lists(st.integers(), max_size=3), max_size=3))
def test_roundrobin_yields_all_items(iterables):
    """Property: roundrobin yields all items from all input iterables."""
    expected_items = []
    for it in iterables:
        expected_items.extend(it)

    actual_items = list(roundrobin(*iterables))

    assert sorted(actual_items) == sorted(expected_items)

@given(st.lists(st.lists(st.integers(), max_size=3), max_size=3))
def test_roundrobin_alternates_sources(iterables):
    """Property: roundrobin alternates between iterables until exhausted."""
    non_empty_iterables = [it for it in iterables if it]
    if len(non_empty_iterables) < 2:
        return

    actual_items = list(roundrobin(*non_empty_iterables))

    source_indices = []
    for item in actual_items:
        for i, it in enumerate(non_empty_iterables):
            if item in it:
                source_indices.append(i)
                break

    for i in range(len(source_indices) - 1):
        assert source_indices[i] != source_indices[i + 1], \
            f"Items at positions {i} and {i+1} both came from iterable {source_indices[i]}"

@given(st.lists(st.lists(st.integers(), max_size=2), min_size=1, max_size=3))
def test_roundrobin_preserves_relative_order(iterables):
    """Property: roundrobin preserves relative order within each iterable."""
    actual_items = list(roundrobin(*iterables))

    for it in iterables:
        if not it:
            continue
        positions = []
        for idx, item in enumerate(actual_items):
            if item in it:
                positions.append(idx)

        for i in range(len(positions) - 1):
            assert positions[i] < positions[i + 1], \
                f"Items from iterable {it} out of order at positions {positions[i]} and {positions[i+1]}"

import pytest
from hypothesis import given, strategies as st
from more_itertools.recipes import iter_except

@given(
    exception=st.just(StopIteration),
    first=st.none()
)
def test_iter_except_yields_until_exception(exception, first):
    """Property: iter_except yields results from func until exception is raised."""
    call_count = 0
    def counting_func():
        nonlocal call_count
        call_count += 1
        if call_count > 3:
            raise exception
        return call_count

    result = list(iter_except(counting_func, exception, first))
    assert result == [1, 2, 3]
    assert call_count == 4

@given(
    exception=st.just(ValueError),
    first=st.none()
)
def test_iter_except_empty_on_immediate_exception(exception, first):
    """Property: iter_except yields empty list if func raises exception immediately."""
    def immediate_exception_func():
        raise exception

    result = list(iter_except(immediate_exception_func, exception, first))
    assert result == []

@given(
    exception=st.just(IndexError),
    first=st.integers(min_value=0, max_value=10)
)
def test_iter_except_with_first_argument(exception, first):
    """Property: iter_except includes first argument as initial yield if provided."""
    call_count = 0
    def counting_func():
        nonlocal call_count
        call_count += 1
        if call_count > 2:
            raise exception
        return call_count

    result = list(iter_except(counting_func, exception, first))
    assert result[0] == first
    assert result[1:] == [1, 2]
    assert call_count == 3

