import pytest
from hypothesis import given, strategies as st
from sortedcontainers.sortedlist import recursive_repr

@given(fillvalue=st.text(alphabet=st.characters(whitelist_categories=('Lu', 'Ll', 'Nd', 'P')), max_size=10))
def test_recursive_repr_decorates_function(fillvalue):
    """Test that recursive_repr returns a decorator that modifies a function's repr behavior."""
    @recursive_repr(fillvalue)
    def dummy_repr(self):
        return "original"

    # The decorated function should still be callable with appropriate arguments
    assert dummy_repr(None) == "original"
    assert callable(dummy_repr)

