    """Test that recursive_repr accepts a fillvalue parameter and uses it in decoration."""
    decorator = recursive_repr(fillvalue)
    assert callable(decorator)

    @decorator
    def another_dummy(self):
        return "test"

    assert another_dummy(None) == "test"

