import pytest
from hypothesis import given, strategies as st
from more_itertools.more import longest_common_prefix

@given(iterables=st.lists(st.text(min_size=0, max_size=5), min_size=1, max_size=3))
def test_longest_common_prefix_yields_common_prefix(iterables):
    """Test that longest_common_prefix yields only elements common to all iterables at each position."""
    result = list(longest_common_prefix(iterables))

    # If there are no common elements, result should be empty
    if not result:
        # Find minimum length among iterables
        min_len = min((len(it) for it in iterables), default=0)

        # Check if all iterables are identical up to min_len
        all_identical = True
        for i in range(min_len):
            if len(set(it[i] for it in iterables)) > 1:
                all_identical = False
                break

        # If all identical up to min_len and all have same length, result should match
        if all_identical and all(len(it) == len(iterables[0]) for it in iterables):
            assert result == list(iterables[0])
        return

    # Check each yielded element is common to all iterables at that position
    for i, elem in enumerate(result):
        for it in iterables:
            if i < len(it):
                assert it[i] == elem
            else:
                # If an iterable is shorter, we shouldn't have yielded beyond its length
                assert False, f"Yielded element at position {i} but iterable {it} has length {len(it)}"

    # Check that the next position (if exists) is not common
    next_pos = len(result)
    if all(len(it) > next_pos for it in iterables):
        # There is at least one differing element at next_pos
        assert len(set(it[next_pos] for it in iterables)) > 1

# Additional test for empty iterables case
