import pytest
from hypothesis import given, strategies as st
from more_itertools.more import chunked

@given(
    iterable=st.lists(st.integers(), min_size=0, max_size=20),
    n=st.integers(min_value=1, max_value=10),
    strict=st.booleans()
)
def test_chunked_length_and_content(iterable, n, strict):
    """Test that chunked yields lists where total elements equal input length and chunks have correct sizes."""
    if strict and len(iterable) % n != 0:
        with pytest.raises(ValueError):
            list(chunked(iterable, n, strict))
    else:
        result = list(chunked(iterable, n, strict))
        # Check total elements preserved
        total_elements = sum(len(chunk) for chunk in result)
        assert total_elements == len(iterable), f"Total elements mismatch: {total_elements} vs {len(iterable)}"
        # Check chunk sizes
        for chunk in result[:-1]:
            assert len(chunk) == n, f"Non-last chunk size {len(chunk)} != n={n}"
        if result and len(iterable) % n == 0:
            assert len(result[-1]) == n, f"Last chunk size {len(result[-1])} != n={n} when divisible"
        elif result and not strict:
            assert len(result[-1]) <= n, f"Last chunk size {len(result[-1])} > n={n}"
        # Check content matches original order
        flat_result = [item for chunk in result for item in chunk]
        assert flat_result == iterable, f"Content mismatch: {flat_result} vs {iterable}"

