def test_split_into_yields_correct_number_of_chunks(iterable, sizes):
    """The number of yielded lists should equal the length of sizes."""
    result = list(split_into(iterable, sizes))
    # When iterable is empty, all chunks are empty, but the number of chunks should still match sizes
    assert len(result) == len(sizes)

@given(
    iterable=st.lists(st.integers(), max_size=10),
    sizes=st.lists(st.integers(min_value=0, max_value=5), max_size=5)
)
def test_split_into_chunk_sizes_match_specified_sizes(iterable, sizes):
    """Each yielded list's length should match the corresponding size, unless iterable is exhausted."""
    result = list(split_into(iterable, sizes))
    remaining = len(iterable)
    for i, (chunk, size) in enumerate(zip(result, sizes)):
        if remaining <= 0:
            assert len(chunk) == 0
        else:
            expected_len = min(size, remaining)
            assert len(chunk) == expected_len
            remaining -= expected_len

@given(
    iterable=st.lists(st.integers(), max_size=10),
    sizes=st.lists(st.one_of(st.none(), st.integers(min_value=0, max_value=5)), max_size=5)
)
def test_split_into_preserves_order_and_content(iterable, sizes):
    """The concatenation of all chunks should equal the prefix of iterable up to the sum of non-None sizes, plus all remaining items if a None is present."""
    result = list(split_into(iterable, sizes))
    flat_result = [item for chunk in result for item in chunk]
    # Calculate expected prefix: sum of non-None sizes, but if a None is encountered, include all remaining items
    total_non_none = 0
    remaining = len(iterable)
    expected_items = []
    for size in sizes:
        if remaining <= 0:
            break
        if size is None:
            expected_items.extend(iterable[total_non_none:])
            break
        else:
            take = min(size, remaining)
            expected_items.extend(iterable[total_non_none:total_non_none + take])
            total_non_none += take
            remaining -= take
    assert flat_result == expected_items

@given(
    iterable=st.lists(st.integers(), max_size=10),
    sizes=st.lists(st.one_of(st.none(), st.integers(min_value=0, max_value=5)), max_size=5)
)
def test_split_into_handles_none_as_remaining_items(iterable, sizes):
    """When a size is None, the corresponding chunk should contain all remaining items."""
    result = list(split_into(iterable, sizes))
    remaining = len(iterable)
    for i, (chunk, size) in enumerate(zip(result, sizes)):
        if size is None:
            assert len(chunk) == remaining
            remaining = 0
        elif remaining <= 0:
            assert len(chunk) == 0
        else:
            expected_len = min(size, remaining)
            assert len(chunk) == expected_len
            remaining -= expected_len

