def test_map_except_yields_transformed_items(iterable, exceptions):
    """map_except should yield items transformed by function, skipping those that raise specified exceptions."""
    def safe_divide(x):
        if x == 0:
            raise ZeroDivisionError
        return x / 2

    result = list(map_except(safe_divide, iterable, *exceptions))

