        try:
            transformed = safe_divide(item)
            if ZeroDivisionError not in exceptions or item != 0:
                assert transformed in result
            else:
                assert transformed not in result
        except ZeroDivisionError:
            if ZeroDivisionError in exceptions:
                assert True  # Item correctly skipped
            else:
                pytest.fail(f"Unexpected ZeroDivisionError for item {item} with exceptions {exceptions}")
