from hypothesis import given, strategies as st
from sortedcontainers.sortedlist import SortedList

@given(
    elements=st.lists(st.integers(), max_size=10),
    start=st.one_of(st.none(), st.integers(min_value=-20, max_value=20)),
    stop=st.one_of(st.none(), st.integers(min_value=-20, max_value=20)),
    reverse=st.booleans()
)
def test_islice_produces_correct_slice(elements, start, stop, reverse):
    """Property: islice(start, stop, reverse) yields elements from the sorted list
    in the slice [start:stop] (with None treated as boundaries), in order determined by reverse."""
    sl = SortedList(elements)
    it = sl.islice(start, stop, reverse)
    result = list(it)

    # Determine expected slice based on start and stop
    if start is None:
        effective_start = 0
    elif start < 0:
        effective_start = max(len(sl) + start, 0)
    else:
        effective_start = min(start, len(sl))

    if stop is None:
        effective_stop = len(sl)
    elif stop < 0:
        effective_stop = max(len(sl) + stop, 0)
    else:
        effective_stop = min(stop, len(sl))

    expected = sl[effective_start:effective_stop]
    if reverse:
        expected = list(reversed(expected))

    assert result == expected

