import pytest
from hypothesis import given, strategies as st
from sortedcontainers.sortedlist import SortedKeyList
from operator import neg

@given(
    elements=st.lists(st.integers(min_value=0, max_value=100), max_size=10),
    minimum=st.one_of(st.none(), st.integers(min_value=0, max_value=100)),
    maximum=st.one_of(st.none(), st.integers(min_value=0, max_value=100)),
    inclusive_min=st.booleans(),
    inclusive_max=st.booleans(),
    reverse=st.booleans()
)
def test_irange_iterator_property(elements, minimum, maximum, inclusive_min, inclusive_max, reverse):
    """Property: irange returns an iterator whose elements are within the specified range and order."""
    skl = SortedKeyList(elements, key=neg)
    inclusive = (inclusive_min, inclusive_max)

    result = list(skl.irange(minimum, maximum, inclusive=inclusive, reverse=reverse))

    # Check that all elements are in the original list
    assert all(elem in elements for elem in result), "Iterator returned elements not in original list"

    # Check ordering based on reverse flag
    if reverse:
        assert result == sorted(result, key=neg, reverse=True), "Elements not in reverse order when reverse=True"
    else:
        assert result == sorted(result, key=neg), "Elements not in sorted order when reverse=False"

    # Check range boundaries
    if minimum is not None:
        if inclusive_min:
            assert all(neg(elem) >= neg(minimum) for elem in result), "Minimum inclusive condition violated"
        else:
            assert all(neg(elem) > neg(minimum) for elem in result), "Minimum exclusive condition violated"
    if maximum is not None:
        if inclusive_max:
            assert all(neg(elem) <= neg(maximum) for elem in result), "Maximum inclusive condition violated"
        else:
            assert all(neg(elem) < neg(maximum) for elem in result), "Maximum exclusive condition violated"

