import pytest
from hypothesis import given, strategies as st
from sortedcontainers.sortedlist import SortedList

@given(
    elements=st.lists(st.integers(), max_size=10),
    minimum=st.one_of(st.none(), st.integers()),
    maximum=st.one_of(st.none(), st.integers()),
    inclusive_min=st.booleans(),
    inclusive_max=st.booleans(),
    reverse=st.booleans()
)
def test_irange_iterator_property(elements, minimum, maximum, inclusive_min, inclusive_max, reverse):
    """Test that irange returns an iterator with values between minimum and maximum according to inclusive flags."""
    sl = SortedList(elements)
    inclusive = (inclusive_min, inclusive_max)

    # Get iterator
    iterator = sl.irange(minimum=minimum, maximum=maximum, inclusive=inclusive, reverse=reverse)

    # Convert to list for verification
    result = list(iterator)

    # Filter expected values based on minimum/maximum bounds and inclusive flags
    expected = []
    for value in sorted(elements, reverse=reverse):
        # Check minimum bound
        if minimum is not None:
            if inclusive_min:
                if value < minimum:
                    continue
            else:
                if value <= minimum:
                    continue

        # Check maximum bound
        if maximum is not None:
            if inclusive_max:
                if value > maximum:
                    continue
            else:
                if value >= maximum:
                    continue

        expected.append(value)

    # Verify the result matches expected filtered values
    assert result == expected

