    """Property: The length of the iterable matches the expected behavior based on the docstring."""
    result = list(always_iterable(obj))
    if obj is None:
        assert len(result) == 0, f"For None, expected empty iterable, got {result}"
    elif isinstance(obj, (str, bytes)):
        # Default base_type includes str and bytes, so they are not considered iterable
        assert len(result) == 1, f"For string/bytes {obj}, expected single-item iterable, got {result}"
        assert result[0] == obj, f"For string/bytes {obj}, expected item {obj}, got {result}"
    else:
        # For other types, check if obj is iterable in Python's sense
        try:
            iter(obj)
            is_py_iterable = True
        except TypeError:
            is_py_iterable = False
        if is_py_iterable:
            # If iterable, result should have same items as iterating over obj
            expected = list(obj)
            assert result == expected, f"For iterable {obj}, expected {expected}, got {result}"
