from hypothesis import given, strategies as st
from more_itertools.more import powerset_of_sets

@given(st.lists(st.integers(), max_size=5))
def test_powerset_of_sets_contains_all_subsets(iterable):
    """Property: The result contains all possible subsets of the input iterable."""
    result = list(powerset_of_sets(iterable))
    # Convert input to a set to handle duplicates as per docstring example
    input_set = set(iterable)
    # Generate all subsets of the input set
    expected_subsets = []
    # Use binary representation to generate all subsets
    for i in range(1 << len(input_set)):
        subset = set()
        for j, elem in enumerate(input_set):
            if i & (1 << j):
                subset.add(elem)
        expected_subsets.append(subset)
    # Check that all expected subsets are in the result
    for subset in expected_subsets:
        assert subset in result, f"Missing subset {subset} in result"
    # Check that result contains no extra elements
    assert len(result) == len(expected_subsets), f"Result length {len(result)} does not match expected {len(expected_subsets)}"

