    assert all(isinstance(x, int) for x in result), "Result contains non-integer or nested elements"
    # The flattened result should contain all integers from the original structure
    def collect_ints(obj):
        if isinstance(obj, int):
            return [obj]
        elif isinstance(obj, list):
            return [item for sublist in obj for item in collect_ints(sublist)]
        else:
            return []
    expected_ints = collect_ints(iterable)
    assert sorted(result) == sorted(expected_ints), "Flattened integers do not match original"

@given(st.lists(st.one_of(st.text(max_size=2), st.tuples(st.text(max_size=2), st.text(max_size=2))), max_size=4))
def test_collapse_with_base_type_tuple_preserves_tuples(iterable):
    """With base_type=tuple, collapse should not flatten tuples, but flatten lists."""
    result = list(collapse(iterable, base_type=tuple))
    # Strings and tuples should remain intact, lists should be flattened
    for item in result:
        assert isinstance(item, (str, tuple)), f"Unexpected type {type(item)} in result"
        if isinstance(item, tuple):
            assert all(isinstance(x, str) for x in item), "Tuple contains non-string elements"
    # Verify no nested structures beyond tuples remain
    assert not any(isinstance(x, list) for x in result), "Lists were not fully flattened"

@given(st.lists(st.one_of(st.integers(), st.lists(st.integers(), max_size=2)), max_size=4), st.integers(min_value=0, max_value=2))
def test_collapse_levels_limits_flattening_depth(iterable, levels):
    """Collapse with levels parameter should flatten only up to the specified depth."""
    result = list(collapse(iterable, levels=levels))
    # Helper to check maximum nesting depth in result
    def max_depth(obj, current=0):
        if isinstance(obj, list):
            return max((max_depth(item, current + 1) for item in obj), default=current)
        else:
            return current
    actual_max_depth = max((max_depth(x) for x in result), default=0)
    # After levels flattening, remaining nesting depth should be <= original max depth - levels
    original_max_depth = max_depth(iterable)
    expected_max_depth = max(0, original_max_depth - levels) if levels is not None else 0
    assert actual_max_depth <= expected_max_depth, f"Flattening exceeded level limit: levels={levels}, actual depth={actual_max_depth}"

