import pytest
from hypothesis import given, strategies as st
from sympy.crypto.crypto import padded_key

@given(
    key=st.text(min_size=0, max_size=5, alphabet=st.characters(whitelist_categories=('Lu', 'Ll'))),
    symbols=st.text(min_size=1, max_size=10, alphabet=st.characters(whitelist_categories=('Lu', 'Ll'))).filter(lambda s: len(set(s)) == len(s))
)
def test_padded_key_returns_string_with_key_first_and_no_duplicates(key, symbols):
    """Property: padded_key returns a string where all characters from key appear first,
    followed by remaining distinct characters from symbols, with no duplicates in the result."""
    try:
        result = padded_key(key, symbols)
        # Check that result is a string
        assert isinstance(result, str), "Result must be a string"
        # Remove duplicates from key while preserving order
        key_chars = []
        for char in key:
            if char not in key_chars:
                key_chars.append(char)
        # Filter key_chars to only those in symbols
        key_chars_in_symbols = [c for c in key_chars if c in symbols]
        # Check that filtered key characters appear first in result
        for i, char in enumerate(key_chars_in_symbols):
            assert result[i] == char, f"Character {char} from key should appear at position {i}"
        # Check that result contains only characters from symbols
        assert all(c in symbols for c in result), "Result contains characters not in symbols"
        # Check that result has no duplicate characters
        assert len(set(result)) == len(result), "Result has duplicate characters"
        # Check that length matches distinct characters in symbols
        expected_chars = set(symbols)
        assert len(result) == len(expected_chars), "Result length should match number of distinct symbols"
        # Check that all characters from symbols appear in result
        assert set(result) == expected_chars, "Result should contain all distinct symbols"
    except ValueError as e:
        error_msg = str(e)
        if "duplicate characters in symbols" in error_msg:
            # This should not happen due to our filter, but we handle it
            assert len(set(symbols)) != len(symbols), "ValueError for duplicate symbols should match condition"
        elif "characters in key but not symbols" in error_msg:
            # This can happen when key has characters not in symbols
            assert any(c not in symbols for c in key), "ValueError for key characters not in symbols should match condition"
        else:
            raise AssertionError(f"Unexpected ValueError: {error_msg}")

@given(
    key=st.text(min_size=1, max_size=5, alphabet=st.characters(whitelist_categories=('Lu', 'Ll'))),
    symbols=st.text(min_size=1, max_size=10, alphabet=st.characters(whitelist_categories=('Lu', 'Ll'))).filter(lambda s: len(set(s)) == len(s))
)
def test_padded_key_raises_value_error_for_key_chars_not_in_symbols(key, symbols):
    """Property: padded_key raises ValueError if key contains characters not in symbols."""
    # Only test cases where key has at least one character not in symbols
