@given(
    seq=st.lists(st.integers(), min_size=0, max_size=10),
    n=st.integers(min_value=1, max_value=5),
    fillvalue=st.one_of(st.none(), st.integers()),
    step=st.integers(min_value=1, max_value=3)
)
def test_windowed_length_property(seq, n, fillvalue, step):
    """The number of windows returned should be max(0, (len(seq) - n + step) // step) when n <= len(seq), otherwise 1 if fillvalue is provided."""
    result = list(windowed(seq, n, fillvalue=fillvalue, step=step))
    if n <= len(seq):
        expected_length = max(0, (len(seq) - n + step) // step)
        assert len(result) == expected_length
    else:
        # When n > len(seq), there is exactly one window if fillvalue is provided
        # (even if fillvalue is None), otherwise no windows
        if fillvalue is not None:
            assert len(result) == 1
        else:
            # With fillvalue=None and n > len(seq), the behavior is to return one window
            # with None fillvalues as per the docstring example
            assert len(result) == 1

