    if k <= total_elements:
        result = sample(iterable, k, counts=counts)
        assert len(result) == k
        # Check each element is from iterable and respects counts
        from collections import Counter
        # Create expanded population from counts
        expanded = []
        for elem, cnt in zip(iterable, counts):
            expanded.extend([elem] * cnt)
        # Result should be a subset of expanded without exceeding counts
        result_counts = Counter(result)
        for elem, cnt in result_counts.items():
            # Find the count for this element in the original counts
            elem_count = 0
            for orig_elem, orig_cnt in zip(iterable, counts):
                if orig_elem == elem:
                    elem_count += orig_cnt
            assert cnt <= elem_count
    else:
