from hypothesis import given, strategies as st
from more_itertools.recipes import grouper

@given(
    data=st.lists(st.integers(), min_size=0),
    n=st.integers(min_value=1, max_value=10),
    incomplete=st.sampled_from(['fill', 'ignore', 'strict']),
    fillvalue=st.integers()
)
def test_grouper_output_length(data, n, incomplete, fillvalue):
    """Test that grouper yields groups of correct length n, except possibly the last group based on incomplete mode."""
    try:
        result = list(grouper(data, n, incomplete=incomplete, fillvalue=fillvalue))
        if incomplete == 'ignore':
            # In 'ignore' mode, all groups should have length n
            for group in result:
                assert len(group) == n
            # Total elements in groups should be <= len(data)
            assert sum(len(group) for group in result) <= len(data)
        elif incomplete == 'fill':
            # In 'fill' mode, all groups should have length n
            for group in result:
                assert len(group) == n
            # Total elements in groups should be >= len(data)
            assert sum(len(group) for group in result) >= len(data)
        else:  # incomplete == 'strict'
            # In 'strict' mode, if len(data) % n != 0, ValueError should be raised
            if len(data) % n != 0:
                pytest.fail("Expected ValueError for 'strict' mode with non-multiple length")
            else:
                for group in result:
                    assert len(group) == n
    except ValueError:
        # Only allow ValueError in 'strict' mode when len(data) % n != 0
        if incomplete != 'strict' or len(data) % n == 0:
            raise

