    else:
        with pytest.raises(ValueError):
            sl.remove(value_to_remove)

import pytest
from hypothesis import given, strategies as st
from sortedcontainers.sortedlist import SortedKeyList

@given(st.lists(st.integers(), max_size=10), st.integers())
def test_bisect_key_right_insertion_point_after_existing_keys(items, key):
    """Test that bisect_key_right returns index after existing keys when key is present."""
    skl = SortedKeyList(items, key=lambda x: x)
    index = skl.bisect_key_right(key)

    # Check that all elements before index have keys <= given key
    for i in range(index):
        assert skl.key(skl[i]) <= key

    # Check that all elements at or after index have keys > given key
    for i in range(index, len(skl)):
        assert skl.key(skl[i]) > key

@given(st.lists(st.integers(), max_size=10), st.integers())
def test_bisect_key_right_consistent_with_sorted_order(items, key):
    """Test that inserting at returned index maintains sorted order by key."""
    skl = SortedKeyList(items, key=lambda x: x)
    index = skl.bisect_key_right(key)

    # Create new list with key inserted at index
    new_items = list(items)
    new_items.insert(index, key)
    new_skl = SortedKeyList(new_items, key=lambda x: x)

    # Verify the new list is sorted by key
    for i in range(len(new_skl) - 1):
        assert new_skl.key(new_skl[i]) <= new_skl.key(new_skl[i + 1])

@given(st.lists(st.integers(), max_size=10))
def test_bisect_key_right_range(items):
    """Test that returned index is always within valid range 0 <= index <= len(list)."""
    skl = SortedKeyList(items, key=lambda x: x)
    for key in items + [min(items) - 1 if items else 0, max(items) + 1 if items else 0]:
        index = skl.bisect_key_right(key)
        assert 0 <= index <= len(skl)

import pytest
from hypothesis import given, strategies as st
from sortedcontainers.sorteddict import SortedDict

@given(st.dictionaries(st.text(min_size=1), st.integers(), min_size=1))
def test_popitem_removes_item_and_returns_pair(d):
    sd = SortedDict(d)
    original_len = len(sd)
    key, value = sd.popitem()
    assert (key, value) in d.items()
    assert len(sd) == original_len - 1
    assert key not in sd

@given(st.dictionaries(st.text(min_size=1), st.integers(), min_size=1))
def test_popitem_with_index_removes_correct_item(d):
    sd = SortedDict(d)
    original_items = list(sd.items())
    for i in range(len(sd)):
        sd_copy = SortedDict(d)
        key, value = sd_copy.popitem(i)
        assert (key, value) == original_items[i]
        assert len(sd_copy) == len(sd) - 1
        assert key not in sd_copy

@given(st.dictionaries(st.text(min_size=1), st.integers(), min_size=1))
def test_popitem_default_index_is_last(d):
    sd = SortedDict(d)
    key_default, value_default = sd.popitem()
    key_last, value_last = sd.popitem(-1) if len(sd) > 0 else (None, None)
    sd2 = SortedDict(d)
    if len(sd2) > 0:
