import pytest
from hypothesis import given, strategies as st
from sortedcontainers.sortedlist import SortedKeyList

@given(
    values=st.lists(st.integers(), max_size=10),
    min_key=st.one_of(st.none(), st.integers()),
    max_key=st.one_of(st.none(), st.integers()),
    inclusive=st.tuples(st.booleans(), st.booleans()),
    reverse=st.booleans()
)
def test_irange_key_iterator_property(values, min_key, max_key, inclusive, reverse):
    """Test that irange_key returns an iterator whose elements are within the specified key range and order."""
    skl = SortedKeyList(values)
    iterator = skl.irange_key(min_key, max_key, inclusive=inclusive, reverse=reverse)
    result = list(iterator)

    # Property: All elements in result should be in the original list
    assert all(elem in values for elem in result), "Iterator yielded elements not in original list"

    # Property: Result should be sorted according to reverse flag
    if reverse:
        assert result == sorted(result, reverse=True), "Result not in reverse order when reverse=True"
    else:
        assert result == sorted(result), "Result not in sorted order when reverse=False"

    # Property: If min_key and max_key are None, result should contain all elements (subject to inclusive)
    if min_key is None and max_key is None:
        if inclusive == (True, True):
            assert set(result) == set(values), "With no bounds and inclusive=(True, True), should yield all elements"

    # Property: Check bounds based on inclusive
    if min_key is not None:
        if inclusive[0]:
            assert all(elem >= min_key for elem in result), "Elements should be >= min_key when inclusive[0] is True"
        else:
            assert all(elem > min_key for elem in result), "Elements should be > min_key when inclusive[0] is False"
    if max_key is not None:
        if inclusive[1]:
            assert all(elem <= max_key for elem in result), "Elements should be <= max_key when inclusive[1] is True"
        else:
            assert all(elem < max_key for elem in result), "Elements should be < max_key when inclusive[1] is False"

